'use strict';

var $pow = require('math-intrinsics/pow');

module.exports = function bytesAsFloat64(rawBytes) {
	

	
	var sign = rawBytes[7] & 0x80 ? -1 : 1; 
	var exponent = ((rawBytes[7] & 0x7F) << 4) 
        | ((rawBytes[6] & 0xF0) >> 4); 
	var mantissa = ((rawBytes[6] & 0x0F) * 0x1000000000000) 
        + (rawBytes[5] * 0x10000000000) 
        + (rawBytes[4] * 0x100000000) 
        + (rawBytes[3] * 0x1000000) 
        + (rawBytes[2] * 0x10000) 
        + (rawBytes[1] * 0x100) 
        + rawBytes[0]; 

	if (exponent === 0 && mantissa === 0) {
		return sign * 0;
	}
	if (exponent === 0x7FF && mantissa !== 0) {
		return NaN;
	}
	if (exponent === 0x7FF && mantissa === 0) {
		return sign * Infinity;
	}

	exponent -= 1023; 

	
	if (exponent === -1023) {
		return sign * mantissa * 5e-324; 
	}

	return sign * (1 + (mantissa / 0x10000000000000)) * $pow(2, exponent);
};
